content.rawQuery:
SELECT count ( Distinct  conversation_id )  as  conversation_id 
FROM Cred.Output_BRCP
WHERE    {apply_filters}  and escalation_results = 'Not Met';

SELECT count ( Distinct  conversation_id )  as  conversation_id 
FROM Cred.Output_BRCP
WHERE    {apply_filters}  and escalation_results = 'Met';
